        row_str += f"{row[2]:.0f}".ljust(col_widths[2]) + " | "
        row_str += f"{row[3]:.4f}".ljust(col_widths[3]) + " | "
        row_str += f"{row[4]:.4f}".ljust(col_widths[4]) + " | "
